function StructDreamTripEventInfo:CreateByPb(pb)
	self.eventId = tonumber(pb.eventId)

	self.index = pb.index

	self.eventRefId = pb.eventRefId

	self.eventType = gModelFastDreamTrip:GetDreamTripEventTypeByRefId(self.eventRefId)

	local moreInfo = pb.moreInfo
	self.moreInfo = self:DisposeMoreInfo(moreInfo)

	self.reward = {}
	local reward = pb.reward
	for i,v in ipairs(reward) do
		table.insert(self.reward,{
			itemId = v.itemId,
			itemNum = tonumber(v.count),
			itemType = v.type,
		})
	end

	-- 0 未开始 1 进行中 2 已完成
	self.state = pb.state

	self.oldEventRefId = pb.oldEventRefId
end

function StructDreamTripEventInfo:DisposeMoreInfo(moreInfo)
	local list = {}
	if moreInfo == "" then return list end
	local moreInfoList = string.split(moreInfo,",")
	local moreInfoData,key,value
	for idx,val in ipairs(moreInfoList) do
		moreInfoData = string.split(val,"=")
		key,value = moreInfoData[1],moreInfoData[2]
		local tList = list[key]
		if not tList then
			tList = {}
			list[key] = tList
		end
		if key == StructDreamTripEventInfo.SHOP_ITEM then						-- 商品数据Key， 以|分隔
			local valueList = string.split(value,"|")
			for i,v in ipairs(valueList) do
				v = string.split(v,":")
				table.insert(tList,{
					shopRefId = tonumber(v[1]),
					buyNum = tonumber(v[2]),
				})
			end
		elseif key == StructDreamTripEventInfo.QUEST_INFO then					-- 题目数据Key， 以|分隔
			local valueList = string.split(value,"|")
			for i,v in ipairs(valueList) do
				v = string.split(v,":")
				table.insert(tList,{
					questRefId = tonumber(v[1]),
					answer = v[2],
				})
			end
		elseif key == StructDreamTripEventInfo.INIT_EVENT_ID then				-- 初始事件IdKey ， 初始事件refId
			table.insert(tList,{initEventId = tonumber(value)})
		elseif key == StructDreamTripEventInfo.REWARD then						-- 奖励
		elseif key == StructDreamTripEventInfo.BOOM_ROLL then					-- 炸弹事件退后步数
			table.insert(tList,{subIndex = tonumber(value)})
		elseif key == StructDreamTripEventInfo.FEATHER_ROLL then				-- 羽毛事件选择点数
		elseif key == StructDreamTripEventInfo.MORA_INFO then					-- 猜拳信息
			local valueList = string.split(value,"|")
			for i,v in ipairs(valueList) do
				v = string.split(v,":")
				local myShow,youShow = tonumber(v[1]),tonumber(v[2])
				local win,winStatus
				if myShow == ModelDreamTrip.CQ_JIANDAO then
					if youShow == ModelDreamTrip.CQ_BU then
						win = StructDreamTripEventInfo.TYPE_FG_WIN
						winStatus = StructDreamTripEventInfo.STATUS_FG_WIN
					else
						if youShow == ModelDreamTrip.CQ_JIANDAO then
							winStatus = StructDreamTripEventInfo.STATUS_FG_DOGFALL
						elseif youShow == ModelDreamTrip.CQ_SHITOU then
							winStatus = StructDreamTripEventInfo.STATUS_FG_FAIL
						end
						win = StructDreamTripEventInfo.TYPE_FG_FAIL
					end
				elseif myShow == ModelDreamTrip.CQ_SHITOU then
					if youShow == ModelDreamTrip.CQ_JIANDAO then
						win = StructDreamTripEventInfo.TYPE_FG_WIN
						winStatus = StructDreamTripEventInfo.STATUS_FG_WIN
					else
						if youShow == ModelDreamTrip.CQ_SHITOU then
							winStatus = StructDreamTripEventInfo.STATUS_FG_DOGFALL
						elseif youShow == ModelDreamTrip.CQ_BU then
							winStatus = StructDreamTripEventInfo.STATUS_FG_FAIL
						end
						win = StructDreamTripEventInfo.TYPE_FG_FAIL
					end
				elseif myShow == ModelDreamTrip.CQ_BU then
					if youShow == ModelDreamTrip.CQ_SHITOU then
						win = StructDreamTripEventInfo.TYPE_FG_WIN
						winStatus = StructDreamTripEventInfo.STATUS_FG_WIN
					else
						if youShow == ModelDreamTrip.CQ_BU then
							winStatus = StructDreamTripEventInfo.STATUS_FG_DOGFALL
						elseif youShow == ModelDreamTrip.CQ_JIANDAO then
							winStatus = StructDreamTripEventInfo.STATUS_FG_FAIL
						end
						win = StructDreamTripEventInfo.TYPE_FG_FAIL
					end
				end
				table.insert(tList,{
					myShow = myShow,
					youShow = youShow,
					myWin = win,
					winStatus = winStatus,
				})
			end
		elseif key == StructDreamTripEventInfo.MONSTER_REF_ID then				-- 怪物表的refId
			table.insert(tList,{monsterId = tonumber(value)})
		elseif key == StructDreamTripEventInfo.MONSTER_ADD_COST then			-- 怪物加成信息
			table.insert(tList,{monsterAddCost = tonumber(value)})
		elseif key == StructDreamTripEventInfo.ROBBER_BATTLE then				-- 盗宝者战斗位置
			table.insert(tList,{battleIdx = tonumber(value)})
		elseif key == StructDreamTripEventInfo.ROBBER_LOSER then				-- 盗宝者是否可以投降
			table.insert(tList,{loser = tonumber(value)})

		--- 7.13新增字段
		elseif key == StructDreamTripEventInfo.ROBBER_INIT_INDEX then			-- 盗宝者出生位置
			table.insert(tList,{roberInitIndex = tonumber(value)})
		elseif key == StructDreamTripEventInfo.ROBBER_BACK_COUNT then			-- 盗宝者放过次数
			table.insert(tList,{roberBackCount = tonumber(value)})
		elseif key == StructDreamTripEventInfo.ROBBER_STATE then			 	-- 盗宝者状态  0：未战斗，1：战斗胜利
			table.insert(tList,{roberState = tonumber(value)})


		--- 7.18新增字段
		elseif key == StructDreamTripEventInfo.TURNTABLE_RESULT then
			local valueList = string.split(value,"|")
			local allNum = 0
			local rewardIdList = {}
			local rewardIdKeyList = {}
			for i,v in ipairs(valueList) do
				v = tonumber(v)
				table.insert(rewardIdList,v)
				rewardIdKeyList[v] = v
				allNum = allNum + 1
			end
			table.insert(tList,{
				allNum = allNum,
				rewardIdList = rewardIdList,
				rewardIdKeyList = rewardIdKeyList,
			})
		elseif key == StructDreamTripEventInfo.DIVINATION_RESULT then
			local valueList = string.split(value,"|")
			table.insert(tList,{
				divinationRefId = tonumber(valueList[1]),
				textRefId = tonumber(valueList[2]),
				divinationEffRefId = tonumber(valueList[3]),
			})
		elseif key == StructDreamTripEventInfo.ENCOUNTER_HERO then
			local valueList = string.split(value,"|")
			local heroList = {}
			for i,v in ipairs(valueList) do
				v = tonumber(v)
				table.insert(heroList,v)
			end
			table.insert(tList,{
				heroList = heroList,
			})



		--- 7.20 新增字段
		elseif key == StructDreamTripEventInfo.BYROAD_CHOSE then
			--- 字段配置是=分割，服务端下发用照配置表格下发，需要特殊处理 例如：byroad_chose=1=27=32=33
			table.insert(tList,{
				direType = tonumber(moreInfoData[2]),
				gridIndex = tonumber(moreInfoData[3]),
				gridEndIndex = tonumber(moreInfoData[4]),
				gridLinkIndex = tonumber(moreInfoData[5]),
			})
		end
	end
	return list
end

function StructDreamTripEventInfo:CheckIsFinishEvent()
	return self.state == 2
end

function StructDreamTripEventInfo:GetServerData()
	return {
		index = self.index,
		eventId = self.eventId,
		eventRefId = self.eventRefId,
		moreInfo = self.moreInfo,
		reward = self.reward,
		state = self.state,
		eventType = self.eventType,
		oldEventRefId = self.oldEventRefId
	}
end

